const targetId = args.hostile_id;
const target = bot.entities[targetId];
if (!target) {
  return "<NOT FOUND>: Entity with ID " + targetId + " is not in range or does not exist.";
}
if (args.weapon) {
  const normalize = function (name) {
    return name.toLowerCase().replace(/[^a-z0-9_]/g, '');
  };
  const req = normalize(args.weapon);
  const weaponItem = bot.inventory.items().find(function (item) {
    return normalize(item.name).includes(req) || (item.displayName && normalize(item.displayName).includes(req));
  });
  if (weaponItem) {
    await bot.equip(weaponItem, 'hand');
  }
}
const sleep = function (ms) { return new Promise(function (r) { setTimeout(r, ms); }); };
startBackgroundSkill(bot, 'attack_hostile_by_id', async function (token) {
  const movements = new Movements(bot);
  bot.pathfinder.setMovements(movements);
  const canContinue = function () {
    const currentTarget = bot.entities[targetId];
    const isAlive = currentTarget && (currentTarget.health === undefined || currentTarget.health > 0);
    return !token.cancelled && bot.health > 0 && Boolean(bot.entity) && isAlive;
  };
  bot.pathfinder.setGoal(new goals.GoalFollow(target, 2.5), true);
  while (canContinue()) {
    if (!bot.physicsEnabled) {
      await sleep(100);
      continue;
    }
    const currentTarget = bot.entities[targetId];
    if (!currentTarget) break;
    const reach = 3.8;
    const dist = bot.entity.position.distanceTo(currentTarget.position);
    if (dist <= reach) {
      const eyeHeight = currentTarget.height || 1.6;
      await bot.lookAt(currentTarget.position.offset(0, eyeHeight, 0), true);
      bot.attack(currentTarget);
    }
    await sleep(600);
  }
  bot.pathfinder.setGoal(null);
});
return "<ATTACKING>: Chasing and attacking entity ID " + targetId + (args.weapon ? " using " + args.weapon : "") + ".";

const targetX = Math.floor(args.x);
const targetZ = Math.floor(args.z);
const radius = args.radius;

startBackgroundSkill(bot, 'move_to_coordinate', async function (token) {
  while (!token.cancelled && bot.health > 0 && Boolean(bot.entity)) {
    if (!bot.physicsEnabled) {
      await new Promise(function (resolve) { setTimeout(resolve, 100); });
      continue;
    }

    const movements = new Movements(bot);
    bot.pathfinder.setMovements(movements);

    // Using GoalXZ when radius is small ensures the bot doesn't fail due to Y-level mismatch at the coordinate.
    // Using GoalNear with current Y when radius is large allows for broad positioning.
    const goal = (radius > 1) 
      ? new goals.GoalNear(targetX, Math.floor(bot.entity.position.y), targetZ, radius) 
      : new goals.GoalXZ(targetX, targetZ);

    try {
      await bot.pathfinder.goto(goal);
      return; // Exit if pathing succeeded
    } catch (error) {
      if (token.cancelled) return;
      // If it failed, wait a bit before background task potentially retries or completes
      await new Promise(function (resolve) { setTimeout(resolve, 1000); });
      return;
    }
  }
});

return "<MOVING>: Moving toward (" + targetX + ", " + targetZ + ") with a reach radius of " + radius + ".";
